/* eslint-disable no-bitwise */

// eslint-disable-next-line require-await
export async function convertBlobToArrayBuffer(blob) {
  return new Promise(resolve => {
    const reader = new FileReader();
    reader.onload = () => {
      resolve(reader.result);
    };
    reader.readAsArrayBuffer(blob);
  });
}
export { default as WebsocketMSE } from "./WebsocketMse";
export const buildFullClientRequestBody = params => {
  const req_json = JSON.stringify(params);
  const encoder = new TextEncoder();
  const payload = encoder.encode(req_json);
  const request = new ArrayBuffer(payload.length + 8); // header(4 bytes) + payload_size(4 bytes) + payload
  const header = new DataView(request, 0, 8);
  header.setUint32(0, 0x11101000, false); // big endian
  header.setUint32(4, payload.length, false); // payload size, big endian
  new Uint8Array(request, 8).set(payload); // set payload
  return new Blob([request]);
};
export const decodeAudioOnlyResponse = (buffer, callback, getWordTimeStamp) => {
  let dv = new DataView(buffer);
  // const protocal_version = dv.getUint8(0) >> 4;
  const header_size = (dv.getUint8(0) & 0x0f) * 4;
  const message_type = dv.getUint8(1) >> 4;
  const message_type_specific_flags = dv.getUint8(1) & 0x0f;
  // const serialization_method = dv.getUint8(2) >> 4;
  const message_compression = dv.getUint8(2) & 0x0f;
  // const reserved = dv.getUint8(3);
  const payload = buffer.slice(header_size);
  dv = new DataView(payload);
  if (message_type === 0xb) {
    // audio-only server response
    if (message_type_specific_flags === 0) {
      // ack, no audio data
      return;
    }
    const sequence_number = dv.getInt32(0, false);
    // const payload_size = dv.getUint32(4, false);
    const audio = payload.slice(8);

    // all audio fragments received (sequence_number < 0)
    callback(audio, sequence_number < 0);
  } else if (message_type === 0xc) {
    if (message_compression === 1) {
      console.info({
        message_compression
      });
    }
    const description = new TextDecoder().decode(payload.slice(4));
    getWordTimeStamp === null || getWordTimeStamp === void 0 || getWordTimeStamp(description);
  } else if (message_type === 0xf) {
    // error message from server
    const error_code = dv.getInt32(0, false);
    // const msg_size = dv.getInt32(4, false);
    const error_msg = new TextDecoder().decode(payload.slice(8));
    callback(new ArrayBuffer(0), true, {
      error_code,
      error_msg
    });
  } else {
    // undefined message type
    // eslint-disable-next-line no-throw-literal
    throw `服务异常: 未定义的消息类型:${message_type}`;
  }
};